const items = $input.all();
const first = items[0]?.json;
const skus = Array.isArray(first?.value) ? first.value : (Array.isArray(first) ? first : []);

const SKU_FRIENDLY_NAMES = {
  'SPE_E3': 'Microsoft 365 E3',
  'SPE_E5': 'Microsoft 365 E5',
  'SPE_F1': 'Microsoft 365 F3',
  'SPB': 'Microsoft 365 Business Premium',
  'O365_BUSINESS_PREMIUM': 'Microsoft 365 Business Standard',
  'O365_BUSINESS_ESSENTIALS': 'Microsoft 365 Business Basic',
  'ENTERPRISEPACK': 'Office 365 E3',
  'ENTERPRISEPREMIUM': 'Office 365 E5',
  'ENTERPRISEWITHSCAL': 'Office 365 E4',
  'STANDARDPACK': 'Office 365 E1',
  'DESKLESSPACK': 'Office 365 F3',
  'EXCHANGEENTERPRISE': 'Exchange Online (Plan 2)',
  'EXCHANGESTANDARD': 'Exchange Online (Plan 1)',
  'EMS': 'Enterprise Mobility + Security E3',
  'EMSPREMIUM': 'Enterprise Mobility + Security E5',
  'AAD_PREMIUM': 'Microsoft Entra ID P1',
  'AAD_PREMIUM_P2': 'Microsoft Entra ID P2',
  'FLOW_FREE': 'Microsoft Power Automate Free',
  'MCOMEETADV': 'Microsoft 365 Audio Conferencing',
  'Microsoft_365_Copilot': 'Microsoft 365 Copilot',
  'Microsoft_Teams_Premium': 'Microsoft Teams Premium',
  'Microsoft_365_Copilot_ ': 'Microsoft 365 Copilot',
  'Microsoft_365_Copilot': 'Microsoft 365 Copilot',
  'POWER_BI_STANDARD': 'Power BI (free)',
  'Power_Pages_vTrial_for_Makers': 'Power Pages vTrial for Makers',
  'PROJECTPROFESSIONAL': 'Planner and Project Plan 3',
  'RIGHTSMANAGEMENT_ADHOC': 'Azure Information Protection (Ad Hoc)',
  'Teams_Premium_(for_Departments)': 'Teams Premium (for Departments)',
  'WACONEDRIVEENTERPRISE': 'OneDrive for Business (Plan 2)',
  'Microsoft_365_Copilot ': 'Microsoft 365 Copilot'
};

function genericTitleCase(skuPartNumber) {
  return skuPartNumber
    .replace(/_/g, ' ')
    .split(' ')
    .map(word => {
      if (!word) return word;
      const isAcronym = word.length <= 4 && word === word.toUpperCase() && /^[A-Z0-9]+$/.test(word);
      if (isAcronym) return word;
      return word.charAt(0).toUpperCase() + word.slice(1).toLowerCase();
    })
    .join(' ');
}

function friendlyName(skuPartNumber) {
  if (SKU_FRIENDLY_NAMES[skuPartNumber]) return SKU_FRIENDLY_NAMES[skuPartNumber];
  return genericTitleCase(skuPartNumber);
}

const ALLOWED_SKUS = ['EXCHANGEENTERPRISE', 'MCOMEETADV', 'O365_BUSINESS_ESSENTIALS', 'O365_BUSINESS_PREMIUM', 'Microsoft_365_Copilot', 'Microsoft_Teams_Premium', 'WACONEDRIVEENTERPRISE', 'PROJECTPROFESSIONAL'];

const licenseOptions = skus.filter(s => ALLOWED_SKUS.includes(s.skuPartNumber)).map(s => {
  const total = s.prepaidUnits?.enabled ?? 0;
  const consumed = s.consumedUnits ?? 0;
  const available = total - consumed;
  return { option: `${friendlyName(s.skuPartNumber)} (${available} available)` };
}).sort((a, b) => a.option.localeCompare(b.option));

if (licenseOptions.length === 0) throw new Error('No license options built.');

return [{ json: { dropdownOptions: { licenseType: licenseOptions } } }];

const items = $input.all();

const optionsItem = items.find(item =>
  item.json.dropdownOptions &&
  typeof item.json.dropdownOptions === 'object' &&
  !Array.isArray(item.json.dropdownOptions)
);

const workflowItem = items.find(item => Array.isArray(item.json.nodes));

if (!optionsItem) throw new Error('Could not find dropdownOptions input.');
if (!workflowItem) throw new Error('Could not find workflow JSON input.');

const dropdownOptions = optionsItem.json.dropdownOptions;
const workflow = workflowItem.json;

const formTriggerNode = workflow.nodes.find(node =>
  node.type === 'n8n-nodes-base.formTrigger' ||
  String(node.type || '').includes('formTrigger')
);

if (!formTriggerNode) throw new Error('Could not find Form Trigger node in target workflow.');

formTriggerNode.parameters.formFields = {
  values: [
    { fieldLabel: 'First Name', requiredField: true },
    { fieldLabel: 'Last Name', requiredField: true },
    {
      fieldLabel: 'License Type',
      fieldType: 'checkbox',
      fieldOptions: { values: dropdownOptions.licenseType },
      requiredField: true
    }
  ]
};

const ALLOWED_SETTINGS_KEYS = ['saveExecutionProgress', 'saveManualExecutions', 'saveDataErrorExecution', 'saveDataSuccessExecution', 'executionOrder', 'executionTimeout', 'timezone', 'errorWorkflow'];
const filteredSettings = {};
for (const key of ALLOWED_SETTINGS_KEYS) {
  if (workflow.settings && workflow.settings[key] !== undefined) filteredSettings[key] = workflow.settings[key];
}

const workflowObject = {
  name: workflow.name,
  nodes: workflow.nodes,
  connections: workflow.connections || {},
  settings: filteredSettings
};

return [{
  json: {
    workflowId: workflow.id,
    workflowObjectJson: JSON.stringify(workflowObject)
  }
}];
